import React, { useState } from 'react';
import { Copy, CheckCircle } from 'lucide-react';

const HowToDraftPleadings = () => {
  const [copiedIndex, setCopiedIndex] = useState(null);

  const handleCopy = (text, index) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  return (
    <div className="h-screen overflow-y-auto bg-gradient-to-br from-gray-900 via-slate-900 to-gray-900 p-8">
      <div className="max-w-6xl mx-auto space-y-8 pb-12">
        <h1 className="text-4xl font-bold text-white text-center sticky top-0 bg-gray-900/80 backdrop-blur-sm py-4 z-10">
          How to Draft Pleadings
        </h1>

        {/* Text Sections - All Full Width */}
        <div className="space-y-8">
          {Array.from({ length: 10 }).map((_, index) => (
            <div key={`text-${index}`} className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
              <h2 className="text-2xl text-white mb-4">Título {index + 1}</h2>
              <p className="text-white text-[12px] leading-relaxed">
                Tu texto aquí
              </p>
            </div>
          ))}
        </div>

        {/* Copy Box Sections - All Full Width */}
        <div className="space-y-8">
          {Array.from({ length: 10 }).map((_, index) => (
            <div key={`copy-${index}`} className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl text-white">Copy Box {index + 1}</h3>
                <button
                  onClick={() => handleCopy(`Tu texto aquí para ${index + 1}`, index)}
                  className="text-white hover:text-blue-300 transition-colors"
                  title="Copy to Clipboard"
                >
                  {copiedIndex === index ? (
                    <CheckCircle className="w-5 h-5 text-green-500" />
                  ) : (
                    <Copy className="w-5 h-5" />
                  )}
                </button>
              </div>
              <div className="bg-slate-900/80 rounded-lg p-4">
                <pre className="text-white text-[12px] whitespace-pre-wrap">
                  Tu texto aquí
                </pre>
              </div>
            </div>
          ))}
        </div>

        {/* Image + Text Sections - All Full Width */}
        <div className="space-y-8">
          {Array.from({ length: 6 }).map((_, index) => (
            <div key={`image-${index}`} className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
              <h3 className="text-xl text-white mb-4">Imagen {index + 1}</h3>
              <img 
                src={`/api/placeholder/500/300`} 
                alt={`Imagen ${index + 1}`} 
                className="rounded-lg mb-4 w-full"
              />
              <p className="text-white text-[12px] leading-relaxed">
                Tu texto aquí
              </p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default HowToDraftPleadings;
